n, target = map(int, input().split())
arr = list(map(int, input().split()))
l, r = 0, n-1
while l < r:
    s = arr[l] + arr[r]
    if s == target:
        print(l+1, r+1)
        break
    elif s < target:
        l += 1
    else:
        r -= 1

